from flask import Flask, request, jsonify
from functools import wraps
import jwt
import sqlite3
from datetime import datetime, timedelta
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'your-secret-key')

# Mock database setup
def init_db():
    conn = sqlite3.connect('tokens.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS access_tokens
                 (token TEXT PRIMARY KEY, user_id TEXT, expires_at TIMESTAMP, scopes TEXT)''')
    conn.commit()
    conn.close()

# Token validation function
def validate_token(token):
    conn = sqlite3.connect('tokens.db')
    c = conn.cursor()
    c.execute("SELECT user_id, expires_at, scopes FROM access_tokens WHERE token = ?", (token,))
    result = c.fetchone()
    conn.close()
    
    if not result:
        return None
    
    user_id, expires_at, scopes = result
    expires_at = datetime.fromisoformat(expires_at)
    
    if datetime.utcnow() > expires_at:
        return None
    
    return {'user_id': user_id, 'scopes': scopes.split(',') if scopes else []}

# Decorator for requiring OAuth
def require_oauth(scopes=None):
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            auth_header = request.headers.get('Authorization')
            if not auth_header or not auth_header.startswith('Bearer '):
                return jsonify({'error': 'Missing or invalid authorization header'}), 401
            
            token = auth_header.split(' ')[1]
            token_data = validate_token(token)
            
            if not token_data:
                return jsonify({'error': 'Invalid or expired token'}), 401
            
            # Scope validation
            if scopes:
                token_scopes = token_data.get('scopes', [])
                if not all(scope in token_scopes for scope in scopes):
                    return jsonify({'error': 'Insufficient scopes'}), 403
            
            request.token_data = token_data
            return f(*args, **kwargs)
        return decorated_function
    return decorator

