# Token creation endpoint (for testing)
@app.route('/token', methods=['POST'])
def create_token():
    # In a real implementation, this would be a separate auth server
    user_id = request.json.get('user_id', 'test_user')
    scopes = request.json.get('scopes', ['read:user'])
    
    # Create a mock token
    token = jwt.encode({
        'user_id': user_id,
        'scopes': scopes,
        'exp': datetime.utcnow() + timedelta(hours=1)
    }, app.config['SECRET_KEY'], algorithm='HS256')
    
    # Store in database
    conn = sqlite3.connect('tokens.db')
    c = conn.cursor()
    c.execute("INSERT OR REPLACE INTO access_tokens VALUES (?, ?, ?, ?)",
              (token, user_id, datetime.utcnow() + timedelta(hours=1), ','.join(scopes)))
    conn.commit()
    conn.close()
    
    return jsonify({'access_token': token, 'token_type': 'Bearer'})

